// Score → user-friendly label (no "Exceptional", "Challenging", "Needs Remedies")
function friendlyLabel(s) {
  if (s >= 75) return { en:'Strong support',      hi:'मजबूत साथ',            ta:'வலுவான ஆதரவு',      te:'బలమైన మద్దతు',      bn:'শক্তিশালী সমর্থন',   mr:'भक्कम पाठिंबा',      pa:'ਮਜ਼ਬੂਤ ਸਾਥ',        gu:'મજબૂત ટેકો',       color:'#10B981' };
  if (s >= 60) return { en:'Supportive',           hi:'सहायक',                ta:'ஆதரவான',           te:'మద్దతునిచ్చే',      bn:'সহায়ক',            mr:'सहाय्यक',            pa:'ਸਹਾਇਕ',            gu:'સહાયક',           color:'#22C55E' };
  if (s >= 45) return { en:'Balanced with effort', hi:'प्रयास से संतुलित',    ta:'முயற்சியால் சமநிலை', te:'ప్రయత్నంతో సమతుల్యం', bn:'প্রচেষ্টায় ভারসাম্যপূর্ণ', mr:'प्रयत्नाने संतुलित', pa:'ਮਿਹਨਤ ਨਾਲ ਸੰਤੁਲਿਤ', gu:'પ્રયત્નથી સંતુલિત', color:'#F59E0B' };
  if (s >= 30) return { en:'Needs extra care',     hi:'अतिरिक्त ध्यान जरूरी', ta:'கூடுதல் கவனம் தேவை', te:'అదనపు శ్రద్ధ అవసరం', bn:'অতিরিক্ত যত্ন প্রয়োজন', mr:'अतिरिक्त काळजी आवश्यक', pa:'ਵਾਧੂ ਧਿਆਨ ਲੋੜੀਂਦਾ', gu:'વધારાની કાળજી જરૂરી', color:'#F97316' };
  return             { en:'Handle carefully',      hi:'सावधानी से संभालें',   ta:'கவனமாக கையாளுங்கள்', te:'జాగ్రత్తగా నిర్వహించండి', bn:'সাবধানে সামলান',   mr:'काळजीपूर्वक हाताळा', pa:'ਸਾਵਧਾਨੀ ਨਾਲ ਸੰਭਾਲੋ', gu:'સાવધાનીથી સંભાળો', color:'#EF4444' };
}

