function domainFriendlyLabel(score) {
  if (score >= 65) return { en:'Flowing',       hi:'अनुकूल',       ta:'சாதகம்',        te:'అనుకూలం',     bn:'অনুকূল',       mr:'अनुकूल',       pa:'ਅਨੁਕੂਲ',       gu:'અનુકૂળ',       color:'#10B981' };
  if (score >= 50) return { en:'Balanced',       hi:'संतुलित',      ta:'சமநிலை',        te:'సమతుల్యం',    bn:'ভারসাম্যপূর্ণ', mr:'संतुलित',      pa:'ਸੰਤੁਲਿਤ',      gu:'સંતુલિત',      color:'#22C55E' };
  if (score >= 36) return { en:'With care',      hi:'ध्यान रखें',   ta:'கவனத்துடன்',    te:'జాగ్రత్తతో',   bn:'যত্ন সহকারে',  mr:'काळजीपूर्वक',  pa:'ਧਿਆਨ ਨਾਲ',     gu:'કાળજી સાથે',   color:'#F59E0B' };
  return                   { en:'Needs nurture', hi:'पोषण जरूरी',   ta:'பராமரிப்பு தேவை', te:'పోషణ అవసరం', bn:'যত্ন প্রয়োজন', mr:'पोषण आवश्यक', pa:'ਪਾਲਣ ਦੀ ਲੋੜ',  gu:'સંવર્ધન જરૂરી', color:'#F97316' };
}

function domainMeaning(key, score) {
  const m = DOMAIN_MEANINGS[key];
  if (!m) return { en:'This area of life is active.', hi:'जीवन का यह क्षेत्र सक्रिय है।', ta:'வாழ்க்கையின் இந்த பகுதி சுறுசுறுப்பாக உள்ளது.', te:'జీవితంలోని ఈ విభాగం క్రియాశీలంగా ఉంది.', bn:'জীবনের এই ক্ষেত্র সক্রিয়।', mr:'जीवनाचा हा भाग सक्रिय आहे.', pa:'ਜੀਵਨ ਦਾ ਇਹ ਖੇਤਰ ਸਰਗਰਮ ਹੈ।', gu:'જીવનનો આ ક્ષેત્ર સક્રિય છે.' };
  if (score >= 65) return m.good;
  if (score >= 42) return m.mid;
  return m.care;
}

