// joiner + count-terminated sentence differ subtly; keep a per-lang template
const YOGA_LIST = {
  en:(t,parts,note)=>`${t} auspicious combination${t !== 1 ? 's' : ''} found: ${parts}. ${note}`,
  hi:(t,parts,note)=>`${t} शुभ संयोजन मिले: ${parts}। ${note}`,
  ta:(t,parts,note)=>`${t} சுப சேர்க்கைகள்: ${parts}. ${note}`,
  te:(t,parts,note)=>`${t} శుభ యోగాలు: ${parts}. ${note}`,
  bn:(t,parts,note)=>`${t}টি শুভ যোগ: ${parts}। ${note}`,
  mr:(t,parts,note)=>`${t} शुभ संयोजने: ${parts}. ${note}`,
  pa:(t,parts,note)=>`${t} ਸ਼ੁਭ ਸੰਯੋਜਨ: ${parts}। ${note}`,
  gu:(t,parts,note)=>`${t} શુભ સંયોજન: ${parts}. ${note}`,
};

// Returns a language-keyed object { en, hi, ta, … }.
function buildYogaSummary(strength, judgement) {
  const yogaArea = (judgement?.areas || []).find(a => a.areaKey === 'yogas');
  const activated = yogaArea?.yogas || [];

  if (!activated.length) {
    const count = strength.yoga_count || 0;
    const out = {};
    for (const lang of ALL_LANGS) out[lang] = count > 0 ? YOGA_FOUND[lang](count) : YOGA_NONE[lang];
    return out;
  }

  const full    = activated.filter(y => y.activation === 'full').length;
  const partial = activated.filter(y => y.activation === 'partial').length;
  const weak    = activated.filter(y => y.activation === 'weak').length;
  const blocked = activated.filter(y => y.activation === 'blocked').length;
  const total   = activated.length;
  const buckets = [['full', full], ['partial', partial], ['weak', weak], ['blocked', blocked]];

  const out = {};
  for (const lang of ALL_LANGS) {
    const parts = buckets.filter(([, n]) => n).map(([k, n]) => YOGA_FRAG[k][lang](n)).join(', ');
    const note = full > 0 ? YOGA_NOTE_ACTIVE[lang] : YOGA_NOTE_BUILD[lang];
    out[lang] = YOGA_LIST[lang](total, parts, note);
  }
  return out;
}

function dashaLevel(score) {
  if (score >= 65) return 'strong';
  if (score >= 45) return 'balanced';
  return 'needs-care';
}

