function buildDashaSummary(strength) {
  const maha  = strength.current_mahadasha;
  const antar = strength.current_antardasha;
  if (!maha) return null;

  const mahaScore  = maha.score || 50;
  const antarScore = antar?.score || 50;
  const support    = dashaLevel(strength.dasha_score || 50);

  const mahaPair  = planetPair(maha.planet);
  const antarPair = antar ? planetPair(antar.planet) : null;
  const txt = DASHA_TEXT[support] || DASHA_TEXT.balanced;

  const simpleMeaning = {}, advice = {};
  for (const lang of ALL_LANGS) {
    const period = antar
      ? `${L(mahaPair, lang)} ${DASHA_WORD.maha[lang]} / ${L(antarPair, lang)} ${DASHA_WORD.antar[lang]}`
      : `${L(mahaPair, lang)} ${DASHA_WORD.maha[lang]}`;
    simpleMeaning[lang] = txt.simple[lang](period);
    advice[lang]        = txt.advice[lang];
  }

  return {
    ...langFields('mahaLord', mahaPair),
    mahaLord:    maha.planet,      // kept for backward compat (admin)
    mahaLordHi:  mahaPair.hi,
    mahaScore,
    mahaEndDate: maha.end_date || null,
    ...(antarPair ? langFields('antarLord', antarPair) : {}),
    antarLord:    antar?.planet || null,
    antarLordHi:  antarPair?.hi || null,
    antarScore:   antar ? antarScore : null,
    antarEndDate: antar?.end_date || null,
    ...langFields('simpleMeaning', simpleMeaning),
    ...langFields('advice', advice),
    supportLevel: support,
  };
}

